// Imagine dois inputs com valores '2' e '3'
const a = '2';
const b = '3';

console.log(a + b); // '23' (concatenação)

const na = Number(a);
const nb = Number(b);

if (Number.isNaN(na) || Number.isNaN(nb)) {
  console.error('Entrada inválida');
} else {
  console.log(na + nb); // 5
}
